queries.sparql:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?grade WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasSchool_Grades ?child ; p:hasDistrict ?parent . } GROUP BY ?child }
  ?child p:grade ?grade .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Districts } }
  FILTER(?nf = ?total)
}

